      hireId,
      scores: scored.map((r) => ({
        candidateId: r.candidate.id,
        weighted: r.scores!.weighted,
      })),
    })

    // Find winner (highest weighted score; tiebreak: shorter system_prompt)
    const sorted = [...scored]
      .filter((r) => r.scores)
      .sort((a, b) => {
        const diff = b.scores!.weighted - a.scores!.weighted
        if (Math.abs(diff) > 0.01) return diff
