  anthropic: Anthropic,
  description: string
): Promise<Candidate[]> {
  const response = await anthropic.messages.create({
    model: 'claude-sonnet-4-20250514',
    max_tokens: 2048,
    messages: [
      {
        role: 'user',
        content: `You are a hiring manager at ClawCorp, an autonomous AI organization.

