    )
    .join('\n---\n')

  const response = await anthropic.messages.create({
    model: 'claude-sonnet-4-20250514',
    max_tokens: 1024,
    messages: [
      {
        role: 'user',
        content: `You are evaluating candidates for: "${description}"

${candidateSummaries}

