    response.content[0].type === 'text' ? response.content[0].text : ''
  const jsonMatch = text.match(/\[[\s\S]*\]/)
  if (!jsonMatch) return results

  const scores: Array<{
    candidateId: string
    task_completion: number
    output_quality: number
    autonomy: number
    conciseness: number
  }> = JSON.parse(jsonMatch[0])

