    const weighted =
      s.task_completion * 0.4 +
      s.output_quality * 0.3 +
      s.autonomy * 0.2 +
      s.conciseness * 0.1
    return {
      ...r,
      scores: { ...s, weighted: Math.round(weighted * 100) / 100 },
    }
  })
