    candidates: results.map((r) => ({
      ...r.candidate,
      exitCode: r.exitCode,
      output: r.output,
      scores: r.scores,
    })),
    winner: results
      .filter((r) => r.scores)
      .sort((a, b) => (b.scores?.weighted ?? 0) - (a.scores?.weighted ?? 0))[0]
      ?.candidate.id,
  }

  await writeFile(
    join(dir, `H-${hireId}.json`),
