                          <div className="min-h-0 flex-1 space-y-2.5 overflow-y-auto pr-1">
                            {colTasks.length === 0 && (
                              <div className={`rounded-xl border border-dashed p-3 text-xs ${colTheme.empty}`}>
                                Drop tasks here
                              </div>
