                                className="mission-card animate-rise cursor-grab p-3 active:cursor-grabbing"
                                style={{ animationDelay: `${taskIndex * 0.02}s` }}
                              >
                                <p className="text-sm font-bold leading-snug text-[#24342b]">{t.title}</p>
