import { useEffect, useRef, useState } from 'react'
import { useWebSocket } from './hooks/useWebSocket'

type Agent = {
  id: string
  title: string
  department: string
  description: string
  status: 'idle' | 'running' | 'error'
  reports_to?: string
  subordinates?: string[]
  rank?: string
  team?: string
}

type Team = {
  id: string
  name: string
  executive_sponsor: string
  head: string
  members: string[]
}

type Mission = {
  id: string
  title: string
  type: 'engineering' | 'research'
  status: string
  current_stage: string
  assignee: string | null
  workspace: string | null
  sessions: Record<string, string>
  parent_mission?: string
}

type Message = {
  id: string
  from: string
  to: string
  missionId: string
  type: 'escalate' | 'report'
  question: string | null
  context: string | null
  summary: string | null
  artifacts: string[] | null
  status: 'pending' | 'answered' | 'done'
  answer: string | null
  created_at: string
}

type Task = {
  id: string
  title: string
  status: string
  created_at: string
  feedback: Array<{ text: string; at: string }>
}

type LogLine = {
  id: number
  agentId: string
  missionId: string
  text: string
  kind: 'output' | 'error' | 'system'
}

const STAGES = ['backlog', 'analysis', 'design', 'development', 'testing', 'done']

const STAGE_LABELS: Record<string, string> = {
  backlog: 'Backlog',
  analysis: 'Analysis',
  design: 'Design',
  development: 'Build',
  testing: 'QA',
  done: 'Done',
}

