  created_at: string
}

type Task = {
  id: string
  title: string
  status: string
  created_at: string
  feedback: Array<{ text: string; at: string }>
}

type LogLine = {
  id: number
  agentId: string
  missionId: string
  text: string
  kind: 'output' | 'error' | 'system'
